import React, { useState, useEffect } from "react";
import { Link, useLocation } from "react-router-dom";

const navLinks = [
  { path: "/", label: "Home" },
  { path: "/about", label: "About" },
  { path: "/skills", label: "Skills" },
  { path: "/projects", label: "Projects" },
  { path: "/certifications", label: "Certs" },
  { path: "/contact", label: "Contact" },
];

export default function Navbar() {
  const location = useLocation();
  const [scrolled, setScrolled] = useState(false);
  const [open, setOpen] = useState(false);

  useEffect(() => {
    const fn = () => setScrolled(window.scrollY > 50);
    window.addEventListener("scroll", fn);
    return () => window.removeEventListener("scroll", fn);
  }, []);

  useEffect(() => { setOpen(false); }, [location]);

  return (
    <nav style={{
      position: "fixed", top: 0, left: 0, right: 0, zIndex: 999,
      background: scrolled ? "rgba(9,9,11,0.95)" : "transparent",
      backdropFilter: scrolled ? "blur(16px)" : "none",
      borderBottom: scrolled ? "1px solid rgba(255,255,255,0.06)" : "none",
      transition: "all 0.4s ease",
      padding: "1.1rem 0",
    }}>
      <div className="container-lg d-flex justify-content-between align-items-center">
        {/* Logo */}
        <Link to="/" style={{ textDecoration: "none" }}>
          <span style={{
            fontFamily: "var(--font-display)", fontWeight: 900,
            fontSize: "1.5rem", color: "var(--text)", letterSpacing: "-0.03em",
          }}>
            JY<span style={{ color: "var(--accent)" }}>.</span>
          </span>
        </Link>

        {/* Desktop */}
        <ul className="d-none d-md-flex list-unstyled mb-0 gap-4 align-items-center">
          {navLinks.map((l) => {
            const active = location.pathname === l.path;
            return (
              <li key={l.path}>
                <Link to={l.path} style={{
                  textDecoration: "none",
                  fontSize: "0.75rem", fontWeight: 500,
                  letterSpacing: "0.12em", textTransform: "uppercase",
                  color: active ? "var(--accent)" : "var(--text-muted)",
                  transition: "color 0.2s",
                  paddingBottom: "3px",
                  borderBottom: active ? "1px solid var(--accent)" : "1px solid transparent",
                }}
                  onMouseEnter={e => { if (!active) e.target.style.color = "var(--text)"; }}
                  onMouseLeave={e => { if (!active) e.target.style.color = "var(--text-muted)"; }}
                >
                  {l.label}
                </Link>
              </li>
            );
          })}
        </ul>

        {/* Mobile burger */}
        <button onClick={() => setOpen(!open)} style={{
          background: "none", border: "none",
          color: "var(--text)", fontSize: "1.5rem",
          cursor: "pointer", display: "none",
        }} className="d-md-none">
          <i className={`bi ${open ? "bi-x-lg" : "bi-list"}`}></i>
        </button>
      </div>

      {/* Mobile dropdown */}
      {open && (
        <div style={{
          background: "var(--surface)",
          borderTop: "1px solid var(--border)",
          padding: "0.5rem 0",
        }} className="d-md-none">
          {navLinks.map((l) => (
            <Link key={l.path} to={l.path} style={{
              display: "block", padding: "0.75rem 1.5rem",
              textDecoration: "none", fontSize: "0.9rem",
              color: location.pathname === l.path ? "var(--accent)" : "var(--text)",
              borderBottom: "1px solid var(--border)",
            }}>
              {l.label}
            </Link>
          ))}
        </div>
      )}
    </nav>
  );
}
